def solution(s: str) -> int:
    """返回 s 中不同回文子串的数量。"""
    palindromes = set()
    n = len(s)

    # 分别以每个字符和每对相邻字符为中心向两侧扩展。
    for center in range(2 * n - 1):
        left = center // 2
        right = left + center % 2
        while left >= 0 and right < n and s[left] == s[right]:
            palindromes.add(s[left:right + 1])
            left -= 1
            right += 1
    return len(palindromes)

def solution(array: list[int]) -> int:
    """返回严格递增子序列的最大元素和。"""
    if not array:
        return 0
    # dp[i] 是以 array[i] 结尾的最优和；单独选择当前元素是初值。
    dp = array.copy()
    for i in range(len(array)):
        for j in range(i):
            if array[j] < array[i]:
                dp[i] = max(dp[i], dp[j] + array[i])
    return max(dp)

def solution(array: list[int]) -> int:
    """返回不选择相邻元素时可得到的最大和，允许一个都不选。"""
    skip = take = 0
    for value in array:
        # 新的 take 只能接在此前 skip 后；新的 skip 取此前两种状态较优者。
        skip, take = max(skip, take), skip + value
    return max(skip, take)

def solution(arr: list[int]) -> int:
    """返回到达最后一个下标的最少跳跃次数，不可达时返回 -1。"""
    n = len(arr)
    if n <= 1:
        return 0
    jumps = 0
    current_end = farthest = 0
    for i in range(n - 1):
        farthest = max(farthest, i + arr[i])
        # 扫完当前一跳能覆盖的区间后，必须使用下一跳。
        if i == current_end:
            if farthest == current_end:
                return -1
            jumps += 1
            current_end = farthest
            if current_end >= n - 1:
                return jumps
    return -1

def solution(arr: list[int]) -> int:
    """返回任意连续分段后，各段最大值之和的最大值。"""
    if not arr:
        return 0
    # 正数单独成段才不会损失；非正数合并后只贡献其中最大者。
    positive_sum = sum(value for value in arr if value > 0)
    return positive_sum if positive_sum else max(arr)

def solution(s: str) -> int:
    """返回出现至少两次且两次出现不重叠的最长子串长度。"""
    n = len(s)
    dp = [[0] * (n + 1) for _ in range(n + 1)]
    answer = 0
    for i in range(1, n + 1):
        for j in range(i + 1, n + 1):
            if s[i - 1] == s[j - 1]:
                # j-i 是两个结尾之间的距离，用它限制匹配长度即可避免重叠。
                dp[i][j] = min(dp[i - 1][j - 1] + 1, j - i)
                answer = max(answer, dp[i][j])
    return answer

def solution(array: list[int]) -> int:
    """返回先严格递增、后严格递减的最长子序列长度。"""
    n = len(array)
    if n == 0:
        return 0
    inc = [1] * n
    dec = [1] * n
    for i in range(n):
        for j in range(i):
            if array[j] < array[i]:
                inc[i] = max(inc[i], inc[j] + 1)
    for i in range(n - 1, -1, -1):
        for j in range(i + 1, n):
            if array[j] < array[i]:
                dec[i] = max(dec[i], dec[j] + 1)
    # 峰值在两段中被计算两次，因此减一。
    return max(inc[i] + dec[i] - 1 for i in range(n))

def solution(grid: list[list[int]]) -> int:
    """返回从左上到右下、每步向右或向下的路径最大和。"""
    if not grid or not grid[0]:
        return 0
    dp = [float("-inf")] * len(grid[0])
    dp[0] = 0
    for row in grid:
        for col, value in enumerate(row):
            # dp[col] 尚为来自上方的值，dp[col-1] 已更新为来自左方的值。
            from_left = dp[col - 1] if col else float("-inf")
            dp[col] = max(dp[col], from_left) + value
    return int(dp[-1])

def solution(s: str) -> int:
    """返回最长回文子序列的长度。"""
    n = len(s)
    if n == 0:
        return 0
    dp = [1] * n
    for left in range(n - 2, -1, -1):
        diagonal = 0
        for right in range(left + 1, n):
            old = dp[right]
            if s[left] == s[right]:
                dp[right] = diagonal + 2
            else:
                dp[right] = max(dp[right], dp[right - 1])
            diagonal = old
    return dp[-1]

def solution(intervals: list[list[int]]) -> list[list[int]]:
    """合并所有相交或端点相接的闭区间。"""
    if not intervals:
        return []
    ordered = sorted(intervals)
    merged = [ordered[0].copy()]
    for start, end in ordered[1:]:
        if start <= merged[-1][1]:
            merged[-1][1] = max(merged[-1][1], end)
        else:
            merged.append([start, end])
    return merged

def solution(s1: str, s2: str) -> int:
    """返回两个字符串的最长公共子序列长度。"""
    if len(s1) < len(s2):
        s1, s2 = s2, s1
    dp = [0] * (len(s2) + 1)
    for char1 in s1:
        diagonal = 0
        for j, char2 in enumerate(s2, 1):
            old = dp[j]
            if char1 == char2:
                dp[j] = diagonal + 1
            else:
                dp[j] = max(dp[j], dp[j - 1])
            diagonal = old
    return dp[-1]

def solution(array: list[int], k: int) -> int:
    """返回至多翻转 k 个元素符号后可得到的最大数组和。"""
    # 因为是“至多”而非“恰好”，每个负数最多翻转一次，正数无需翻转。
    values = sorted(array)
    for i, value in enumerate(values):
        if k == 0 or value >= 0:
            break
        values[i] = -value
        k -= 1
    return sum(values)

def solution(matrix: list[list[int]]) -> int:
    """返回二进制矩阵中全 1 正方形的最大面积。"""
    if not matrix or not matrix[0]:
        return 0
    dp = [0] * (len(matrix[0]) + 1)
    best_side = 0
    for row in matrix:
        diagonal = 0
        for col, value in enumerate(row, 1):
            old = dp[col]
            if value == 1:
                # 当前最大边长由左、上、左上三个正方形中的最短边限制。
                dp[col] = min(dp[col], dp[col - 1], diagonal) + 1
                best_side = max(best_side, dp[col])
            else:
                dp[col] = 0
            diagonal = old
    return best_side * best_side

def solution(array: list[int]) -> int:
    """返回通过单位增减使所有元素相等的最小总成本。"""
    if not array:
        return 0
    ordered = sorted(array)
    # 绝对偏差和在任一中位数处取得最小值。
    median = ordered[len(ordered) // 2]
    return sum(abs(value - median) for value in ordered)

def solution(s: str) -> int:
    """返回不重叠的最长相等前缀与后缀长度。"""
    prefix = [0] * len(s)
    matched = 0
    for i in range(1, len(s)):
        while matched and s[i] != s[matched]:
            matched = prefix[matched - 1]
        if s[i] == s[matched]:
            matched += 1
        prefix[i] = matched
    length = prefix[-1] if s else 0
    # 沿 KMP 失配链寻找第一个不超过字符串一半的边界。
    while length * 2 > len(s):
        length = prefix[length - 1]
    return length

def solution(n: str) -> str:
    """返回与 n 数值距离最近且不等于自身的回文数。"""
    value = int(n)
    length = len(n)
    prefix_length = (length + 1) // 2
    prefix = int(n[:prefix_length])
    candidates = {10 ** (length - 1) - 1, 10 ** length + 1}
    for candidate_prefix in (prefix - 1, prefix, prefix + 1):
        if candidate_prefix < 0:
            continue
        left = str(candidate_prefix)
        # 奇数长度不重复中间字符，偶数长度则完整镜像左半边。
        mirrored = left + left[-(2 if length % 2 else 1)::-1]
        candidates.add(int(mirrored))
    candidates.discard(value)
    return str(min(candidates, key=lambda candidate: (abs(candidate - value), candidate)))

def solution(s: str) -> int:
    """返回不含重复字符的最长连续子串长度。"""
    last_seen = {}
    left = answer = 0
    for right, char in enumerate(s):
        # 只有位于当前窗口内的旧位置才会推动左边界。
        if char in last_seen and last_seen[char] >= left:
            left = last_seen[char] + 1
        last_seen[char] = right
        answer = max(answer, right - left + 1)
    return answer

def min_difference(packets: list[int], students: int) -> int:
    # 排序后，最优选择一定对应排序数组中长度为 students 的连续窗口。
    ordered = sorted(packets)
    return min(ordered[i + students - 1] - ordered[i]
               for i in range(len(ordered) - students + 1))

def balanced_word(word: str) -> int:
    if len(word) % 2:
        return -1
    middle = len(word) // 2
    value = lambda part: sum(ord(ch) - ord('a') + 1 for ch in part)
    return int(value(word[:middle]) == value(word[middle:]))

def min_subarray_length(values: list[int]) -> int:
    low, high = min(values), max(values)
    if low == high:
        return 1
    last_low = last_high = -1
    answer = len(values)
    for index, value in enumerate(values):
        if value == low:
            last_low = index
        if value == high:
            last_high = index
        # 最近的一对极值位置给出以当前位置相关的最短候选区间。
        if last_low >= 0 and last_high >= 0:
            answer = min(answer, abs(last_low - last_high) + 1)
    return answer

def minimum_bill_count(amount: int, coins: list[int]) -> int:
    # dp[value] 表示凑出 value 所需的最少硬币数；动态规划适用于非标准币制。
    dp = [amount + 1] * (amount + 1)
    dp[0] = 0
    for value in range(1, amount + 1):
        for coin in coins:
            if coin <= value:
                dp[value] = min(dp[value], dp[value - coin] + 1)
    return dp[amount]

def count_subarrays(values: list[int], target: int) -> int:
    seen = {0: 1}
    prefix = answer = 0
    for value in values:
        prefix += value
        # 若此前前缀为 prefix-target，两前缀之差对应一个目标和子数组。
        answer += seen.get(prefix - target, 0)
        seen[prefix] = seen.get(prefix, 0) + 1
    return answer

def longest_increasing_subarray(values: list[int]) -> int:
    best = current = 1
    for index in range(1, len(values)):
        current = current + 1 if values[index] > values[index - 1] else 1
        best = max(best, current)
    return best

def count_fair_removals(weights: list[int]) -> int:
    total_even = sum(weights[::2])
    total_odd = sum(weights[1::2])
    left_even = left_odd = answer = 0
    for index, weight in enumerate(weights):
        # 删除后右侧下标奇偶性翻转，因此右侧偶数和要加到新奇数侧，反之亦然。
        right_even = total_even - left_even - (weight if index % 2 == 0 else 0)
        right_odd = total_odd - left_odd - (weight if index % 2 else 0)
        if left_even + right_odd == left_odd + right_even:
            answer += 1
        if index % 2 == 0:
            left_even += weight
        else:
            left_odd += weight
    return answer

def expensive_words(sentence: str) -> int:
    total = 0
    for token in sentence.split():
        letters = [char for char in token if char.isalpha()]
        value = sum(ord(char.lower()) - ord('a') + 1 for char in letters)
        # 标点不参与大小写判断；剩余字母全部大写才翻倍。
        if letters and all(char.isupper() for char in letters):
            value *= 2
        total += value
    return total

def rearrange_sentence(sentence: str) -> str:
    placed = []
    for word in sentence.split():
        position = next(int(char) for char in word if char.isdigit())
        clean = ''.join(char for char in word if not char.isdigit())
        placed.append((position, clean))
    return ' '.join(word for _, word in sorted(placed))

def max_sum_column(values: list[int], width: int) -> int:
    sums = [0] * width
    for index, value in enumerate(values):
        sums[index % width] += value
    # list.index 在并列时自然返回最小列号。
    return sums.index(max(sums)) + 1

def encode(message: str, key: int) -> str:
    digits = str(key)
    sums = []
    for index, char in enumerate(message):
        letter_value = ord(char) - ord('a') + 1
        sums.append(str(letter_value + int(digits[index % len(digits)])))
    return ','.join(sums)

def compress_string(chars: str) -> str:
    counts = {}
    for char in chars:
        counts[char] = counts.get(char, 0) + 1
    parts = []
    for char in counts:  # dict 保持字符首次出现顺序
        parts.append(char if counts[char] == 1 else char + str(counts[char]))
    return ''.join(parts)

def parentheses_score(text: str) -> int:
    stack = [0]
    for char in text:
        if char == '(':
            stack.append(0)
        else:
            inside = stack.pop()
            stack[-1] += 1 if inside == 0 else 2 * inside
    return stack[0]

def count_unique_triplets(values: list[int], target: int) -> int:
    ordered = sorted(values)
    found = set()
    for first in range(len(ordered) - 2):
        left, right = first + 1, len(ordered) - 1
        while left < right:
            total = ordered[first] + ordered[left] + ordered[right]
            if total == target:
                found.add((ordered[first], ordered[left], ordered[right]))
                left += 1
                right -= 1
            elif total < target:
                left += 1
            else:
                right -= 1
    return len(found)

def compare_and_merge(first: str, second: str) -> str:
    i = j = 0
    result = []
    while i < len(first) and j < len(second):
        if first[i] <= second[j]:  # 相等时按规则选择 first
            result.append(first[i]); i += 1
        else:
            result.append(second[j]); j += 1
    result.append(first[i:])
    result.append(second[j:])
    return ''.join(result)

def solution(n, items, bags):
    """判断 items[:n] 能否恰好装进至多 bags 个容量为 10 的袋子。"""
    weights = sorted(items[:n], reverse=True)
    if len(weights) > bags * 10 or sum(weights) > bags * 10:
        return False
    remaining = [10] * bags

    def place(index):
        if index == len(weights):
            return True
        weight = weights[index]
        tried = set()
        for i, capacity in enumerate(remaining):
            # 容量相同的袋子是等价状态，只需尝试其中一个。
            if capacity >= weight and capacity not in tried:
                tried.add(capacity)
                remaining[i] -= weight
                if place(index + 1):
                    return True
                remaining[i] += weight
        return False

    return place(0)

