def solution(n, arr):
    values = list(arr[:n])

    def sort_count(left, right):
        if right - left <= 1:
            return 0
        middle = (left + right) // 2
        count = sort_count(left, middle) + sort_count(middle, right)
        merged, i, j = [], left, middle
        while i < middle and j < right:
            if values[i] <= values[j]:
                merged.append(values[i]); i += 1
            else:
                merged.append(values[j]); j += 1
                # 左半剩余元素均大于 values[j]，一次计入。
                count += middle - i
        merged.extend(values[i:middle]); merged.extend(values[j:right])
        values[left:right] = merged
        return count

    return sort_count(0, len(values))

def minSubarrayLength(n, arr):
    values = arr[:n]
    minimum, maximum = min(values), max(values)
    if minimum == maximum:
        return 1
    answer, last_min, last_max = n, -1, -1
    for i, value in enumerate(values):
        if value == minimum:
            last_min = i
        if value == maximum:
            last_max = i
        if last_min != -1 and last_max != -1:
            answer = min(answer, abs(last_min - last_max) + 1)
    return answer

def solution(numOfsets, arr):
